49:\"https://cdn.getgist.com/attachment_images/76ca6cef08ca8e69ac1e7fbc15004bebbd08ad595ee67e0d7b55d1a9555354bfScreenshot%202023-11-23%20at%2000.50.02.png\";s:8:\"category\";s:5:\"guide\";s:11:\"description\";s:143:\"We have done our best to make the cloud set up as smooth and easy as possible. This guide below will walk you through the process step by step.\";}i:3;a:5:{s:5:\"title\";s:14:\"Cloud and AI +\";s:10:\"follow_url\";s:22:\"https://snipco.de/Minf\";s:9:\"image_url\";s:53:\"https://i3.ytimg.com/vi/rEOC2bIwY-w/maxresdefault.jpg\";s:8:\"category\";s:11:\"new feature\";s:11:\"description\";s:68:\"Code Snippets 3.6 Announcement - AI CodeSnippets - Generate AI Code!\";}}s:8:\"partners\";a:4:{i:0;a:3:{s:5:\"title\";s:9:\"Elementor\";s:10:\"follow_url\";s:22:\"https://snipco.de/KK3d\";s:9:\"image_url\";s:76:\"https://codesnippets.pro/wp-content/uploads/2024/05/Elementor-logo-green.png\";}i:1;a:3:{s:5:\"title\";s:7:\"InstaWP\";s:10:\"follow_url\";s:22:\"https://snipco.de/KK3n\";s:9:\"image_url\";s:68:\"https://codesnippets.pro/wp-content/uploads/2024/05/instawp-logo.png\";}i:2;a:3:{s:5:\"title\";s:11:\"Dynamic.ooo\";s:10:\"follow_url\";s:28:\"https://snipco.de/dynamicooo\";s:9:\"image_url\";s:71:\"https://codesnippets.pro/wp-content/uploads/2025/09/Dynamicooo-Logo.png\";}i:3;a:3:{s:5:\"title\";s:10:\"Crocoblock\";s:10:\"follow_url\";s:22:\"https://snipco.de/KK3l\";s:9:\"image_url\";s:71:\"https://codesnippets.pro/wp-content/uploads/2024/05/crocoblock-logo.png\";}}s:9:\"changelog\";a:4:{s:5:\"3.9.5\";a:2:{s:5:\"Added\";a:1:{s:4:\"core\";a:1:{i:0;s:37:\"Confirmed WordPress 6.9 compatability\";}}s:5:\"Fixed\";a:1:{s:4:\"core\";a:1:{i:0;s:94:\"Improved nonce handling for cloud snippet download and update actions to for enhanced security\";}}}s:5:\"3.9.4\";a:3:{s:5:\"Added\";a:1:{s:4:\"core\";a:3:{i:0;s:91:\"New import functionality to migrate snippets from file uploads with drag-and-drop interface\";i:1;s:139:\"Support for importing snippets from other popular plugins (Header Footer Code Manager, Insert Headers and Footers, Insert PHP Code Snippet)\";i:2;s:80:\"Enhanced file based execution support with improved multisite mode compatibility\";}}s:7:\"Changed\";a:1:{s:4:\"core\";a:1:{i:0;s:48:\"Updated links to more recent documentation pages\";}}s:5:\"Fixed\";a:1:{s:4:\"core\";a:3:{i:0;s:49:\"Fixed multisite capability checks in Plugin class\";i:1;s:92:\"Fixed snippet execution logic for multisite support by centralizing trashed snippet handling\";i:2;s:107:\"Fixed multisite snippet handling to ensure local snippets use correct table and filter out trashed snippets\";}}}s:5:\"3.9.3\";a:2:{s:5:\"Added\";a:1:{s:4:\"core\";a:1:{i:0;s:124:\"end-to-end tests to verify the toggle visual state in the snippets list page, improving UI verification and test reliability\";}}s:5:\"Fixed\";a:1:{s:4:\"core\";a:2:{i:0;s:115:\"Fix missing import of common/direction in src/css/manage.scss to restore correct styling and direction-aware layout\";i:1;s:115:\"Fix toggle activation check to ensure the correct transformation value is used when detecting active/inactive state\";}}}s:5:\"3.9.2\";a:2:{s:7:\"Changed\";a:1:{s:4:\"core\";a:6:{i:0;s:85:\"Introduced a custom scissors icon and updated button title for the TinyMCE extension.\";i:1;s:50:\"Improved back-navigation styling on the edit page.\";i:2;s:78:\"Refined layout for column names and action buttons in the Cloud Snippets list.\";i:3;s:56:\"Enhanced overall styling of cloud-related UI components.\";i:4;s:76:\"Optimized cloud search with more efficient pagination and snippet retrieval.\";i:5;s:83:\"Introduced groundwork to prevent Composer dependency collisions with other plugins.\";}}s:5:\"Fixed\";a:1:{s:4:\"core\";a:2:{i:0;s:80:\"Improved sanitization and normalization across Cloud API and pagination outputs.\";i:1;s:72:\"Resolved various TinyMCE issues reported in the WordPress support forum.\";}}}}}', 'off');
