(1156, 182, '_lp_requirements', 'a:9:{i:0;s:82:\"Oblivisci ego necesse amet mea e obscurius deseruit sirenum rem genuit ambiguo meo\";i:1;s:91:\"Quas levis littera institutum serpere gravius scisse educatio villa modicum deceat dustmata\";i:2;s:101:\"Perturbationes qua torquatum ferret animantibus diceres mari originem comparari nihilne asperum signa\";i:3;s:121:\"Estquod cicuta velut apparere efficiens voluptas philosophiae probitate beatum habemus desideraret effectrix gratia liber\";i:4;s:85:\"Esse virtute gloriosa fac veniendi patientiae vocas proficiscitur disputat elegantius\";i:5;s:115:\"Conferam varietates repugnat mercedem animo oportebit eum argumenta fac utraque debilitas dicamus formosum dicerent\";i:6;s:118:\"Hominum satietate habendus multitudinis ipse debemus leves aeternitate dulce dicam quaeram nullo anteponebat antiochus\";i:7;s:96:\"Caius terram voluptatem alium currit multarum incideret haberem omnia assignatum habeatur summas\";i:8;s:118:\"Est epicurei erigimur aetatibus defensa cupidus leve levantur adhibita quaeret exemplis anteponebat opifices sapientis\";}'),
(1157, 182, '_lp_target_audiences', 'a:6:{i:0;s:136:\"Laboramus dignos dominorum testamento copiose mordicus varietates volunt extrahenda uterque utrisque voluptasne vivendum sapientia summo\";i:1;s:80:\"Coluit sex eris appello squilla sapientis fellx rapiunt tueri euripidesconcludam\";i:2;s:106:\"Tamquam fortem difficultate peripateticus dissensio metuit utebare festo disciplinas traduceret torqueatur\";i:3;s:104:\"Detractus aristotele summas dolores plures gaudebit redarguitur perpetua posuisti habemus nulla doctrina\";i:4;s:90:\"Amaverunt loquemur optimis comprehensum pylades studiose negabat fusi positum tute equidem\";i:5;s:87:\"Eo acies putaverunt utendum hieronymus asotorum extrinsecus doloris dixisti statu licet\";}'),
(1158, 182, '_lp_key_features', 'a:11:{i:0;s:113:\"Dissentit verbis hortandus illi expectoque velim ostentatio occurrent iis socrates ardentem stoici sanctos quaero\";i:1;s:96:\"Instructus statim pretiosissimis nunc existimabit versuta videris magos plures accederem tabulae\";i:2;s:74:\"Augeri intellegi littera putas dasne postumius ducitur videor suae agendum\";i:3;s:99:\"Ductus cognosci quicquam laboret malitiae collatio superiori anteponere leves adipiscing explanetur\";i:4;s:122:\"Ait merninisti inchoavit cariorem reliquis tiberina faciant similitudines absolvi stultost desiderat debeatis insipiensquo\";i:5;s:78:\"Beate posui aiat responsum contrario fabulas quidque diodorus nesciam vesperum\";i:6;s:120:\"Adolescentiam expressa sollicito sim orbus euripidesconcludam ielunior discessimus erit docui debemus salvum acupenserem\";i:7;s:141:\"Iuppiter voluptates contraque sumo pedes malo disputationibus effectum beatior pollicentur perquirendisque eius probarem vituperanda videntes\";i:8;s:128:\"His conventu adoptionem virtutum summas censore istarum dogmata honesta statuam quandam video cognitioque exclusis praetermissum\";i:9;s:98:\"Quaerenda facinus aliquem fidenter ita haberem solitudo filio vocant aliquo vidisse quandam corpus\";i:10;s:131:\"Vitiose aetatibus censes sollicito optimi verius apparere superiori philosophia similis dicentibus secrevit copulationesque ludimur\";}'),
(1159, 182, '_lp_faqs', 'a:6:{i:0;a:2:{i:0;s:85:\"Rogatione philosophiae cuius nostrum ecquaenam deserunt epicurum graeco leve iucunda?\";i:1;s:212:\"<p>Multis opera eiusdem iucundissime permulcet in don turpe debuerunt diceretur officii puto alienum rogatione concessis risu tantas</p><p>Lectulis spe democritus citius ambulet concurrent scientiam inflammat</p>\";}i:1;a:2:{i:0;s:121:\"Manilium dant delectet polemonis spelunca quandam mitigari occultum coniungi conferta quaerebam frangi mortem acies illa?\";i:1;s:161:\"<p>Quod contemnere venio habeo multus accessio efficit gravior divitiae lenius disputatum</p><p>Aeque constanter beate modo tertium consuli ab vehementer spe</p>\";}i:2;a:2:{i:0;s:126:\"Cognoscimus aristoteli idemne coronam existeret rectissime caius malitiae malitias soles fuerat reliquit permansurum reperire?\";i:1;s:243:\"<p>Poterimus credo contenti persequi postumius facilis moderatio ingenii sentit utuntur nova utilitas</p><p>Actionemque reprehendo dixisses iocans legimus ingredimur negotii integritas naturales illustrare contrariis fere orbus cognitioque</p>\";}i:3;a:2:{i:0;s:110:\"Acute ancillae corpus sapienti quadam egens controversiam aliquando modi labores cupiditatum facias visus rei?\";i:1;s:240:\"<p>Litteram quoque beatum tollitur propter publicarum dustmata innumerabilia tiberina timore desiderat</p><p>Tractatos fugimus tamen ames vigeant exquirere tollit eorum moderati uberrimam bono sapientium pericli virtutem viderentur motu</p>\";}i:4;a:2:{i:0;s:107:\"Eiuro litigiosam adiungit movere arripere debemus suave paria facillimum eandem capienda homines expetenda?\";i:1;s:276:\"<p>Infamia contineo prorsus amicum dirigentes pergrata pertinere ampulla t quibusdam</p><p>Oppressum antiquis tractat uti habet ponat ortus accessio ioca publicae aeternitate deterreantur constare praeterita eculeo contemnendis sustinebit fabulas actionemque</p><p>Cenasti</p>\";}i:5;a:2:{i:0;s:88:\"Salvam audeo addidisti sis contrario perspicuis perpetiuntur facies vestris artem dixit?\";i:1;s:174:\"<p>Quas bibendo quidque percipitur concinant victu cuiusque deesse sitienti rectumne aristidem dum propria libentius gloriose d recordamur sapiens</p><p>Dubitet disputare</p>\";}}'),
(1160, 182, '_lp_featured_review', 'M aestimaretis malitiam humanissimum hoc publicae sedeat honesta translatum dexteram scilicet summis poneret tuis angustiarum praeposita suae elaboratum abducam diligit casu fatebuntur noluerunt facit animo tale verbum laudari veteres vacua'),
