\";}i:3;a:5:{s:4:\"data\";s:9:\"Nha Trang\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:26:\"Nha Trang WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:12:\"Recap Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1175\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"Một số hình ảnh sự kiện Nha Trang WordPress Meetup 25/08/2024 sáng nay tại Nha Trang...\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Nguyễn Xuân Bình Minh\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:32065:\"\n<p class=\"wp-block-paragraph\">Một số hình ảnh sự kiện Nha Trang WordPress Meetup 25/08/2024 sáng nay tại Nha Trang</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ban tổ chức trân trọng cám ơn quý anh chị đã tham dự sự kiện.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Có gì sai sót mong quý anh chị thông cảm và bỏ qua giúp BTC ạ.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cám ơn các speaker đã dành thời gian hỗ trợ chương trình.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cám ơn các nhà tài trợ đã hỗ trợ tài chính và quà tặng cho sự kiện.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Hẹn gặp lại quý anh chị vào Nha Trang WordPress Meetup tháng 9/2024</p>\n\n\n\n<figure class=\"wp-block-gallery aligncenter has-nested-images columns-default is-cropped wp-block-gallery-2 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" data-id=\"1261\" src=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42-1024x683.jpg\" alt=\"\" class=\"wp-image-1261\" srcset=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42-1024x683.jpg 1024w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42-300x200.jpg 300w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42-768x513.jpg 768w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-42.jpg 1434w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" data-id=\"1262\" src=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1-1024x683.jpg\" alt=\"\" class=\"wp-image-1262\" srcset=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1-1024x683.jpg 1024w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1-300x200.jpg 300w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1-768x513.jpg 768w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-41-1.jpg 1434w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-17.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" data-id=\"1236\" src=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-17-1024x683.jpg\" alt=\"\" class=\"wp-image-1236\" srcset=\"https://vi.wordpress.org/files/2024/08/NTWP-2024-08-17-1024x683.jpg 1024w, https://vi.wordpress.org/files/2024/08/NTWP-2024-08-17-300x200.jpg 300w, https://vi.wordpress.org/files/2024/