INSERT INTO `wp_snippets` (`id`, `name`, `description`, `code`, `tags`, `scope`, `condition_id`, `priority`, `active`, `modified`, `revision`, `cloud_id`) VALUES
(1, 'Make upload filenames lowercase', 'Makes sure that image and file uploads have lowercase filenames.\n\nThis is a sample snippet. Feel free to use it, edit it, or remove it.', 'add_filter( \'sanitize_file_name\', \'mb_strtolower\' );', 'sample, media', 'global', 0, 10, 0, '2026-03-10 08:15:01', 1, NULL),
(2, 'Disable admin bar', 'Turns off the WordPress admin bar for everyone except administrators.\n\nThis is a sample snippet. Feel free to use it, edit it, or remove it.', 'add_action( \'wp\', function () {\n	if ( ! current_user_can( \'manage_options\' ) ) {\n		show_admin_bar( false );\n	}\n} );', 'sample, admin-bar', 'front-end', 0, 10, 0, '2026-03-10 08:15:01', 1, NULL),
(3, 'Allow smilies', 'Allows smiley conversion in obscure places.\n\nThis is a sample snippet. Feel free to use it, edit it, or remove it.', 'add_filter( \'widget_text\', \'convert_smilies\' );\nadd_filter( \'the_title\', \'convert_smilies\' );\nadd_filter( \'wp_title\', \'convert_smilies\' );\nadd_filter( \'get_bloginfo\', \'convert_smilies\' );', 'sample', 'global', 0, 10, 0, '2026-03-10 08:15:01', 1, NULL),
(4, 'Current year', 'Shortcode for inserting the current year into a post or page..\n\nThis is a sample snippet. Feel free to use it, edit it, or remove it.', '<?php echo date( \'Y\' ); ?>', 'sample, dates', 'content', 0, 10, 0, '2026-03-10 08:15:01', 1, NULL),
(5, 'Demo the_content hook', '', 'add_filter(\'the_content\', function($content){\n    echo \'<p style=\"color:red\">HOOK TEST</p>\';\n    return $content;\n});', '', 'global', 0, 10, 1, '2026-03-10 08:47:32', 1, NULL);
